int set_nonblocking(int fd) {
    int flags = fcntl(fd, F_GETFL, 0);
    if (flags == -1) return -1;
    return fcntl(fd, F_SETFL, flags | O_NONBLOCK);
}

int validate_http_request(const char *buffer, size_t len) {
    if (len < 16) return 0;
    
    if (strncmp(buffer, "GET ", 4) != 0 && 
        strncmp(buffer, "POST ", 5) != 0 &&
        strncmp(buffer, "HEAD ", 5) != 0 &&
        strncmp(buffer, "PUT ", 4) != 0 &&
        strncmp(buffer, "DELETE ", 7) != 0) {
        return 0;
    }
    
    const char *end = strstr(buffer, "\r\n\r\n");
    if (!end) return 0;
    
    if (end - buffer > MAX_HEADER_SIZE) return 0;
    
    return 1;
}

void sanitize_path(char *path, size_t max_len) {
    size_t len = strnlen(path, max_len);
    
    for (size_t i = 0; i < len; i++) {
        if (path[i] == '\0') break;
        if (path[i] < 32 || path[i] > 126) {
            path[i] = '_';
        }
    }
    
    char *dotdot;
    while ((dotdot = strstr(path, "..")) != NULL) {
        memmove(dotdot, dotdot + 2, strlen(dotdot + 2) + 1);
    }
}

int extract_request_path(const char *request, char *path, size_t path_size) {
    const char *start = strchr(request, ' ');
    if (!start) return -1;
    start++;
    
    const char *end = strchr(start, ' ');
    if (!end) return -1;
    
    size_t path_len = end - start;
    if (path_len >= path_size) path_len = path_size - 1;
    
    memcpy(path, start, path_len);
    path[path_len] = '\0';
    
    sanitize_path(path, path_size);
    return 0;
}

